const quickEventLabelByType = Object.fromEntries(delegatedEventDefinitions.map((definition) => [definition.tipoEvento, definition.label]));
const getQuickEventBaseType = (tipoEvento = '') => String(tipoEvento || '').replace(/_rival$/i, '');
const getQuickEventSide = (event = {}) => (
  event.equipo === 'rival' || /_rival$/i.test(String(event.tipoEvento || '')) ? 'rival' : 'caudal'
);
const quickEventMatches = (event, tipoEvento, side = 'caudal') =>
  getQuickEventBaseType(event?.tipoEvento) === tipoEvento && getQuickEventSide(event) === side;
const getDelegatedDefinitionForEvent = (event = {}) =>
  delegatedEventDefinitions.find((definition) => (
    definition.tipoEvento === getQuickEventBaseType(event.tipoEvento) &&
    definition.side === getQuickEventSide(event)
  )) || delegatedEventDefinitions.find((definition) => definition.tipoEvento === getQuickEventBaseType(event.tipoEvento));
const getQuickEventLabel = (tipoEvento = '') => quickEventLabelByType[getQuickEventBaseType(tipoEvento)] || tipoEvento || 'Evento';
const applyEventEffects = (stats, effects = {}) => {
  Object.entries(effects).forEach(([key, value]) => {
    stats[key] = (Number(stats[key]) || 0) + Number(value || 0);
  });
  return stats;
};
const aggregateQuickEventStats = (events = [], { side = 'caudal', playerId = '', scope = 'team' } = {}) => {
  const stats = createEmptyEventStats();
  const sourceEvents = safeArray(events).filter((event) => {
    if (side && getQuickEventSide(event) !== side) return false;
    if (scope === 'player' && (!playerId || event.jugadorId !== playerId)) return false;
    return true;
  });
  sourceEvents.forEach((event) => {
    const effects = EVENT_STAT_EFFECTS[getQuickEventBaseType(event.tipoEvento)]?.[scope] || {};
    applyEventEffects(stats, effects);
  });
  return { ...stats, events: sourceEvents, hasEvents: sourceEvents.length > 0 };
};
const getStatRate = (part, total) => (total > 0 ? `${Math.round((part / total) * 100)}%` : 'No disponible');

const getMatchScoreValues = (match) => {
  const statsEvents = match?.statsGoalEvents || [];
  const statsCaudalGoals = statsEvents.filter((event) => event.type === 'Gol a favor').length;
  const statsRivalGoals = statsEvents.filter((event) => event.type === 'Gol en contra').length;
  const officialGoalEvents = statsEvents.filter((event) => ['Gol a favor', 'Gol en contra'].includes(event.type));
  const hasStatsScore = officialGoalEvents.length > 0;
  const score = getMatchScore(match);
  return {
    statsEvents,
    statsCaudalGoals,
    statsRivalGoals,
    hasStatsScore,
    hasCompleteScore: Boolean(score),
    home: score?.home ?? null,
    away: score?.away ?? null,
    caudal: score?.caudal ?? null,
    rival: score?.rival ?? null,
  };
};

const isMatchPlayedForUi = (match) => getMatchStatus(match) === 'played';

const getMatchOperationalStatus = (match) => {
  if (!isMatchPlayedForUi(match)) {
    const presentation = getMatchStatusPresentation(match);
    return { label: presentation.label.toUpperCase(), className: 'border-white/15 bg-white/[0.055] text-slate-300' };
  }
  if ((match?.events || []).some((event) => event.reviewed)) {
    return { label: 'ANALIZADO', className: 'border-emerald-200/25 bg-emerald-200/[0.10] text-emerald-100' };
  }
  if ((match?.events || []).length) {
    return { label: 'EN REVISIÓN', className: 'border-sky-200/25 bg-sky-200/[0.10] text-sky-100' };
  }
  return { label: 'CERRADO', className: 'border-white/15 bg-white/[0.055] text-slate-300' };
};

