const normalizeMatch = (match) => {
  const competitionKey = normalizeCompetitionKey(match);
  const competitionMeta = getCompetitionMeta(competitionKey);
  const merged = {
    ...emptyMatchForm,
    ...match,
    id: match.id ?? Date.now(),
    competitionKey: competitionKey === 'other' ? (match.competitionKey || '') : competitionKey,
    type: competitionKey === 'other' ? (match.type || '') : competitionMeta.label,
  };

  return {
    ...merged,
    preAiAnalysis: normalizePreAiAnalysis(merged.preAiAnalysis),
    statsCalledPlayers: safeArray(merged.statsCalledPlayers),
    preCaudalLineup: safeArray(merged.preCaudalLineup),
    preRivalLineup: safeArray(merged.preRivalLineup),
    preRivalLineupPlayers: safeArray(merged.preRivalLineupPlayers),
    preKeyMatchupsTable: safeArray(merged.preKeyMatchupsTable),
    prePlayerNotes: safeObject(merged.prePlayerNotes),
    preRivalPlayerNotes: safeObject(merged.preRivalPlayerNotes),
  };
};

const cleanTeamDisplayName = (name) => name.replace(/^Plantilla\s+/i, '').trim();
const isEmailLikeValue = (value) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(value || '').trim());
const getSafeRivalNameInput = (value) => {
  const cleanName = cleanTeamDisplayName(String(value || ''));
  return isEmailLikeValue(cleanName) ? '' : cleanName;
};
const getRivalFormDisplayName = (value) => getSafeRivalNameInput(value) || 'Rival sin nombre';
const comparableTeamName = (name) =>
  cleanTeamDisplayName(name || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]/gi, '')
    .toLowerCase();
const findTeamByDisplayName = (teams, name) => {
  const comparableName = comparableTeamName(name);
  if (!comparableName) return null;
  return teams.find((team) => comparableTeamName(team.name) === comparableName) ?? null;
};

const getMatchResult = (match) => {
  const outcome = getMatchOutcome(match);
  return outcome === 'win' ? 'W' : outcome === 'loss' ? 'L' : outcome === 'draw' ? 'D' : null;
};

const matchDisplayDate = (date) => {
  if (!date) return '-';
  const [year, month, day] = date.split('-');
  return day && month && year ? `${day}/${month}/${year}` : date;
};

const extractImportedPlayers = (text) => {
  const ignored = new Set([
    'jugador',
    'jugadores',
    'plantilla',
    'equipo',
    'posición',
    'nacionalidad',
    'edad',
    'altura',
    'peso',
    'valor de mercado',
  ]);

  return Array.from(
    new Set(
      text
        .split('\n')
        .map((line) =>
          line
            .replace(/\[|\]|\*|#/g, '')
            .replace(/Image:\s*/gi, '')
            .replace(/\s{2,}/g, ' ')
            .trim()
        )
        .filter((line) => {
          const lower = line.toLowerCase();
          return (
            line.length >= 5 &&
            line.length <= 45 &&
            /[a-záéíóúñü]/i.test(line) &&
            !ignored.has(lower) &&
            !lower.includes('http') &&
            !lower.includes('temporada') &&
            !lower.includes('copyright') &&
            !/^\d/.test(line)
          );
        })
        .slice(0, 35)
    )
  ).map((name) => ({ name, image: '' }));
};

const normalizeSourceUrl = (value) => {
  const trimmed = value.trim();
  if (!trimmed) return '';
  return /^https?:\/\//i.test(trimmed) ? trimmed : `https://${trimmed}`;
};

const getReadableUrls = (sourceUrl) => {
  const normalized = normalizeSourceUrl(sourceUrl);
  const noProtocol = normalized.replace(/^https?:\/\//i, '');

  return [
    normalized,
    `https://api.allorigins.win/raw?url=${encodeURIComponent(normalized)}`,
    `https://r.jina.ai/${normalized}`,
    `https://r.jina.ai/http://${noProtocol}`,
  ];
};

const extractTeamName = (doc, fallback) => {
  const heading = doc.querySelector('h1')?.textContent?.trim();
  const title = doc.querySelector('meta[property="og:title"]')?.content || doc.title;
  return heading || title?.replace(/\s*[-|].*$/, '').trim() || fallback;
};

const extractStadium = (doc) => {
  const text = (doc.body?.textContent || '').replace(/\s+/g, ' ').trim();
  const labelMatch = text.match(/(?:Estadio|Campo|Campo de juego)\s*:?\s*([A-ZÁÉÍÓÚÑÜ][A-Za-zÁÉÍÓÚÑÜáéíóúñü0-9 .'-]{2,70})/i);
  if (labelMatch) return labelMatch[1].replace(/\s+(Aforo|Capacidad|Dirección|Direccion|Ciudad).*$/i, '').trim();

  const tableMatch = Array.from(doc.querySelectorAll('tr, li, p, div'))
    .map((node) => node.textContent?.replace(/\s+/g, ' ').trim() || '')
    .find((value) => /^(Estadio|Campo|Campo de juego)\b/i.test(value));

  return tableMatch?.replace(/^(Estadio|Campo|Campo de juego)\s*:?\s*/i, '').replace(/\s+(Aforo|Capacidad|Dirección|Direccion|Ciudad).*$/i, '').trim() || '';
};

const extractKitColor = (doc) => {
  const themeColor = doc.querySelector('meta[name="theme-color"]')?.content;
  if (/^#[0-9a-f]{6}$/i.test(themeColor || '')) return themeColor;

  const raw = doc.documentElement?.outerHTML ?? '';
  const colors = raw.match(/#[0-9a-f]{6}\b/gi) || [];
  const ignored = new Set(['#ffffff', '#000000', '#f8fafc', '#f5f5f5', '#eeeeee', '#e5e7eb']);
  return colors.find((color) => !ignored.has(color.toLowerCase())) || '';
};

const resolveAssetUrl = (value, baseUrl) => {
  if (!value) return '';
  try {
    return new URL(value, baseUrl).href;
  } catch {
    return value;
  }
};

const getImageSource = (img, baseUrl) =>
  resolveAssetUrl(
    img?.getAttribute('data-src') ||
      img?.getAttribute('data-original') ||
      img?.getAttribute('data-lazy') ||
      img?.getAttribute('src') ||
      '',
    baseUrl
  );

const isTransfermarktUrl = (url) => /transfermarkt\./i.test(url);
const isBesoccerUrl = (url) => /besoccer\./i.test(url);

const extractCrest = (doc, baseUrl) => {
  const raw = doc.documentElement?.outerHTML ?? '';

  if (isBesoccerUrl(baseUrl)) {
    const besoccerCrest = raw.match(/https?:\/\/[^"'\s)]+(?:img_data\/escudos|media\/img_data\/escudos|img_data\/equipos|media\/img_data\/equipos|\/escudos\/)[^"'\s)]*/i)?.[0];
    if (besoccerCrest) return besoccerCrest.replace(/&amp;/g, '&');

    const teamName = extractTeamName(doc, '');
    const crest =
      Array.from(doc.querySelectorAll('img')).find((img) => {
        const alt = img.alt?.trim() ?? '';
        const src = img.getAttribute('src') ?? '';
        return alt === teamName || /img_data\/escudos|img_data\/equipos|\/escudos\/|shield|team/i.test(src);
      }) ||
      Array.from(doc.querySelectorAll('img')).find((img) => /escudo|equipo|club|team/i.test(`${img.alt} ${img.src}`));
    const crestUrl = getImageSource(crest, baseUrl);
    if (crestUrl && !/flags|avatar|besoccertv|apuestas/i.test(crestUrl)) return crestUrl;
  }

  if (isTransfermarktUrl(baseUrl)) {
    const crest =
      doc.querySelector('.data-header__profile-container img') ||
      doc.querySelector('.data-header__profile-image') ||
      doc.querySelector('header img[alt]') ||
      Array.from(doc.querySelectorAll('img')).find((img) =>
        /wappen|logo|verein|club|data-header/i.test(`${img.className} ${img.src}`)
      );
    const crestUrl = getImageSource(crest, baseUrl);
    if (crestUrl && !/tm_logo|transfermarkt/i.test(crestUrl)) return crestUrl;
  }

  const metaImage = doc.querySelector('meta[property="og:image"]')?.content;
  const crestImage = Array.from(doc.querySelectorAll('img')).find((img) =>
    /escudo|crest|wappen|logo|equipo|team/i.test(`${img.alt} ${img.src}`)
  );
  return getImageSource(crestImage, baseUrl) || resolveAssetUrl(metaImage || '', baseUrl);
};

const normalizeTransfermarktHeader = (value) => normalizePlayerIdentityName(value).replace(/[^a-z0-9#]+/g, ' ').trim();

const getTransfermarktColumnIndexes = (table) => {
  const headers = Array.from(table?.querySelectorAll('thead th') || []).map((header) => normalizeTransfermarktHeader(header.textContent || header.getAttribute('title') || ''));
  const find = (...patterns) => headers.findIndex((header) => patterns.some((pattern) => pattern.test(header)));
  return {
    number: find(/^#$/, /dorsal/, /ruckennummer/, /shirt number/),
    player: find(/jugador/, /^player$/, /spieler/),
    age: find(/edad/, /^age$/, /alter/),
    nationality: find(/nacionalidad/, /^nac\.?$/, /^nat\.?$/, /nationality/, /nation/),
    contractUntil: find(/contrato/, /contract/, /vertrag/),
    marketValue: find(/valor de mercado/, /market value/, /marktwert/),
  };
};

const isTransfermarktPlaceholderPortrait = (url) => /default|kein[-_]?bild|no[-_]?photo|placeholder|avatar|\/portrait\/medium\/default/i.test(String(url || ''));

const parseTransfermarktMarketValue = (value) => {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  if (!text || text === '-') return { marketValueAmount: null, marketValueCurrency: null };
  const numeric = Number((text.match(/[\d.,]+/)?.[0] || '').replace(/\./g, '').replace(',', '.'));
  if (!Number.isFinite(numeric)) return { marketValueAmount: null, marketValueCurrency: null };
  const multiplier = /(?:mil|k)\b/i.test(text) ? 1000 : /(?:mill\.?|mio\.?|m)\b/i.test(text) ? 1000000 : 1;
  return { marketValueAmount: Math.round(numeric * multiplier), marketValueCurrency: /€|eur/i.test(text) ? 'EUR' : null };
};

const parseTransfermarktSquadRow = (row, baseUrl, columnIndexes = {}) => {
  const cells = Array.from(row.children).filter((cell) => cell.tagName === 'TD');
  const cellAt = (index) => index >= 0 ? cells[index] || null : null;
  const nameLink = row.querySelector('td.hauptlink a[href*="/profil/spieler/"], td.hauptlink a[href*="/spieler/"], td.posrela a[href*="/spieler/"], a[href*="/profil/spieler/"]');
  const playerCell = cellAt(columnIndexes.player) || nameLink?.closest('td.posrela') || nameLink?.closest('td');
  const portrait = playerCell?.querySelector('img.bilderrahmen-fixed, img[src*="/portrait/"], img[data-src*="/portrait/"]') || row.querySelector('img.bilderrahmen-fixed');
  const name = (nameLink?.textContent || portrait?.alt || '').replace(/\s+/g, ' ').trim();
  const sourceProfileUrl = resolveAssetUrl(nameLink?.getAttribute('href') || '', baseUrl);
  const rawImage = getImageSource(portrait, baseUrl);
  const image = isTransfermarktPlaceholderPortrait(rawImage) ? '' : rawImage;
  const inlineRowTexts = Array.from(playerCell?.querySelectorAll('.inline-table tr') || [])
    .map((inlineRow) => inlineRow.textContent?.replace(/\s+/g, ' ').trim() || '')
    .filter(Boolean);
  const normalizedName = normalizePlayerIdentityName(name);
  const rawPosition = inlineRowTexts.find((text) => {
    const normalizedText = normalizePlayerIdentityName(text);
    return normalizedText && normalizedText !== normalizedName && !normalizedText.includes(normalizedName);
  }) || '';
  const numberText = (cellAt(columnIndexes.number)?.textContent || row.querySelector('.rn_nummer')?.textContent || '').trim();
  const parsedNumber = Number(numberText.match(/\d{1,2}/)?.[0]);
  const ageCell = cellAt(columnIndexes.age) || cells.find((cell) => /^(edad|age|alter)$/i.test(cell.getAttribute('data-header') || cell.getAttribute('title') || ''));
  const parsedAge = Number((ageCell?.textContent || '').trim());
  const nationalityCell = cellAt(columnIndexes.nationality) || cells.find((cell) => cell.querySelector('img.flaggenrahmen'));
  const nationalityImage = nationalityCell?.querySelector('img');
  const nationality = (nationalityImage?.getAttribute('title') || nationalityImage?.alt || nationalityCell?.textContent || '').trim();
  const nationalityCodeCandidate = nationalityImage?.getAttribute('data-country-code') || nationalityImage?.getAttribute('data-code') || nationalityImage?.alt || '';
  const nationalityCode = /^[a-z]{2,3}$/i.test(nationalityCodeCandidate.trim()) ? nationalityCodeCandidate.trim().toUpperCase() : '';
  const contractText = (cellAt(columnIndexes.contractUntil)?.textContent || '').trim();
  const marketValueText = (cellAt(columnIndexes.marketValue)?.textContent || '').trim();
  return {
    number: Number.isInteger(parsedNumber) && parsedNumber > 0 && parsedNumber < 100 ? String(parsedNumber) : null,
    name,
    image: image || null,
    sourceProfileUrl,
    rawPosition,
    age: Number.isInteger(parsedAge) && parsedAge > 14 && parsedAge < 60 ? parsedAge : null,
    nationality: nationality || null,
    nationalityCode: nationalityCode || null,
    contractUntil: normalizeImportedDob(contractText) || null,
    ...parseTransfermarktMarketValue(marketValueText),
  };
};

const extractTransfermarktPlayers = (doc, baseUrl) => {
  const byName = new Map();
  const table = doc.querySelector('table.items');
  const rows = Array.from(table?.tBodies?.[0]?.children || []).filter((row) => row.tagName === 'TR');
  const columnIndexes = getTransfermarktColumnIndexes(table);

  rows.forEach((row) => {
    const parsed = parseTransfermarktSquadRow(row, baseUrl, columnIndexes);
    const { name, image, sourceProfileUrl, rawPosition, age, number } = parsed;
    const externalPlayerId = extractTransfermarktPlayerId(sourceProfileUrl);
    const positionModel = normalizeImportedPosition(rawPosition);
    const { position, specificPosition } = positionModel;

    if (
      name &&
      name.length > 2 &&
      name.length < 45 &&
      !/transfermarkt|laliga|bundesliga|premier|segunda|serie|ligue|deadline|club siero/i.test(name)
    ) {
      byName.set(externalPlayerId || sourceProfileUrl || name, {
        id: externalPlayerId ? `transfermarkt:${externalPlayerId}` : name,
        name,
        image,
        imageSource: image ? 'imported' : null,
        sourceProfileUrl,
        externalSource: 'transfermarkt',
        externalPlayerId: externalPlayerId || '',
        number,
        rawPosition,
        ...positionModel,
        position,
        specificPosition,
        age,
        height: '',
        foot: '',
        nationality: parsed.nationality,
        nationalityCode: parsed.nationalityCode,
        contractUntil: parsed.contractUntil,
        marketValueAmount: parsed.marketValueAmount,
        marketValueCurrency: parsed.marketValueCurrency,
        role: '',
        isKey: false,
      });
    }
  });
  const players = Array.from(byName.values());
  console.table(players.map((player) => ({ name: player.name, rawPosition: player.rawPosition, position: player.position, specificPosition: player.specificPosition, age: player.age, number: player.number })));
  console.info('[TRANSFERMARKT_SQUAD_IMPORT]', {
    title: doc.title,
    headers: Array.from(table?.querySelectorAll('thead th') || []).map((header) => header.textContent?.trim() || ''),
    total: players.length,
    withName: players.filter((player) => player.name).length,
    withPosition: players.filter((player) => player.position).length,
    withAge: players.filter((player) => Number.isInteger(player.age)).length,
    withNumber: players.filter((player) => player.number).length,
  });
  return players;
};

const normalizeImportedDob = (value) => {
  const text = String(value || '').trim().toLowerCase();
  const numeric = text.match(/\b(\d{1,2})[./-](\d{1,2})[./-](\d{4})\b/);
  if (numeric) return `${numeric[3]}-${numeric[2].padStart(2, '0')}-${numeric[1].padStart(2, '0')}`;
  const months = { enero: 1, febrero: 2, marzo: 3, abril: 4, mayo: 5, junio: 6, julio: 7, agosto: 8, septiembre: 9, octubre: 10, noviembre: 11, diciembre: 12, january: 1, february: 2, march: 3, april: 4, may: 5, june: 6, july: 7, august: 8, september: 9, october: 10, november: 11, december: 12 };
  const written = text.match(/\b(\d{1,2})\s+(?:de\s+)?([a-záéíóúñ]+)\s+(?:de\s+)?(\d{4})\b/i);
  const month = written ? months[normalizePlayerIdentityName(written[2])] : null;
  return written && month ? `${written[3]}-${String(month).padStart(2, '0')}-${written[1].padStart(2, '0')}` : '';
};

const extractTransfermarktPlayerProfile = (doc, baseUrl, player) => {
  const text = (doc.body?.textContent || '').replace(/\s+/g, ' ').trim();
  const dobLabel = text.match(/(?:fecha de nacimiento|geburtsdatum|date of birth)\s*:?\s*([^|]{0,70})/i)?.[1] || text;
  const dob = normalizeImportedDob(dobLabel);
  const heightLabel = text.match(/(?:altura|größe|height)\s*:?\s*([^|]{0,30})/i)?.[1] || '';
  const footLabel = text.match(/(?:pie|fuß|foot)\s*:?\s*([^|]{0,30})/i)?.[1] || '';
  const positionLabel = text.match(/(?:posición|position)\s*:?\s*([^|]{0,55})/i)?.[1] || '';
  const positionModel = normalizeImportedPosition(positionLabel);
  const { position, specificPosition } = positionModel;
  const portrait = doc.querySelector('.data-header__profile-container img, .data-header__profile-image, img[src*="/portrait/"]');
  const image = getImageSource(portrait, baseUrl);
  const number = text.match(/(?:dorsal|shirt number)\s*:?[#\s]*(\d{1,2})/i)?.[1] || '';
  return normalizeSquadEntry({
    ...player,
    dob: dob || player.dob,
    age: dob ? String(calculateAge(dob)) : player.age,
    height: normalizeImportedHeight(heightLabel) || player.height,
    foot: normalizeImportedFoot(footLabel) || player.foot,
    position: position || player.position,
    specificPosition: specificPosition || player.specificPosition,
    ...(positionModel.primaryNaturalPosition ? positionModel : {}),
    image: image || player.image,
    imageSource: image ? 'imported' : player.imageSource,
    number: number || player.number,
  });
};

const extractBesoccerPlayers = (doc, baseUrl) => {
  const byName = new Map();
  const squadScope =
    doc.querySelector('table') ||
    doc.querySelector('[class*="squad"]') ||
    doc.querySelector('[class*="plantilla"]') ||
    doc.body;
  const playerLinks = Array.from(squadScope.querySelectorAll('a[href*="/jugador/"]'));

  playerLinks.forEach((link) => {
    const name = link.textContent?.replace(/\s+/g, ' ').trim();
    const row = link.closest('tr') || link.closest('li') || link.closest('article') || link.parentElement;
    const rowText = row?.textContent?.replace(/\s+/g, ' ').trim() || '';
    const image = getImageSource(link.querySelector('img') || row?.querySelector('img'), baseUrl);
    const sourceProfileUrl = resolveAssetUrl(link.getAttribute('href') || '', baseUrl);
    const number = rowText.match(/(?:^|\s)#?(\d{1,2})(?:\s|$)/)?.[1] || '';
    const age = rowText.match(/(\d{2})\s*a(?:ños?)?/i)?.[1] || '';
    const height = normalizeImportedHeight(rowText);
    const foot = normalizeImportedFoot(rowText);
    const rawPosition = rowText.match(/\b(Portero|Goalkeeper|POR|GK|Defensa central|Centre-Back|Central|Lateral derecho|Lateral izquierdo|Pivote|Mediocentro|Mediapunta|Extremo derecho|Extremo izquierdo|Delantero centro|Delantero|Forward|Striker)\b/i)?.[1] || '';
    const positionModel = normalizeImportedPosition(rawPosition);
    const { position, specificPosition } = positionModel;
    if (name && name.length > 2 && name.length < 45 && !/mas|más|comparar|partidos|trayectoria/i.test(name)) {
      byName.set(sourceProfileUrl || name, {
        id: sourceProfileUrl || name,
        name,
        image,
        imageSource: image ? 'imported' : '',
        sourceProfileUrl,
        ...positionModel,
        number,
        position,
        specificPosition,
        age,
        height,
        foot,
        role: '',
        isKey: false,
      });
    }
  });

  return Array.from(byName.values());
};

const cleanImportedName = (value) =>
  value
    .replace(/\[\d+[^\]]*?([^\]]+)\]/g, '$1')
    .replace(/\[|\]|\*|#/g, '')
    .replace(/Image:\s*/gi, '')
    .replace(/\s{2,}/g, ' ')
    .trim();

const isLikelyPlayerName = (value) => {
  const lower = value.toLowerCase();
  return (
    value.length >= 3 &&
    value.length <= 45 &&
    /[a-záéíóúñü]/i.test(value) &&
    !/plantilla|porteros|defensas|centrocampistas|delanteros|rendimiento|info|totales|edad|rating|temporada|image:|pj|pt|cm|€|seleccionar|copyright|jugadores destacados|máximo goleador|más sancionado|minutos/i.test(lower) &&
    !/^\d+$/.test(value) &&
    !/^\d+\s*(k|m)?\.?€?$/i.test(value)
  );
};

const extractBesoccerPlayersFromText = (text) => {
  const start = text.search(/#\s*Plantilla|##\s*Plantilla|Plantilla\s+.+\s*\|/i);
  const scoped = start >= 0 ? text.slice(start) : text;
  const end = scoped.search(/\n##\s*(Jugadores destacados|Temporada|Últimos|Noticias|Estadio|Fichajes)|Copyright/i);
  const rosterText = end > 0 ? scoped.slice(0, end) : scoped;
  const byName = new Map();
  let currentPosition = '';
  const positionLabels = {
    Desconocido: '',
    Porteros: 'Portero',
    Defensas: 'Defensa central',
    Centrocampistas: 'Mediocentro',
    Delanteros: 'Delantero centro',
  };

  rosterText.split('\n').forEach((rawLine) => {
    const line = rawLine.trim();
    if (/^(Desconocido|Porteros|Defensas|Centrocampistas|Delanteros)\s*\|/i.test(line)) {
      const groupName = line.split('|')[0].trim();
      currentPosition = positionLabels[groupName] ?? groupName;
    }
    if (!line.includes('|') || !/Image:| \| \| /i.test(line)) return;
    if (/---|PJ\s*\||PT\s*\||Edad|rating|Temp/i.test(line)) return;

    const cells = line.split('|').map(cleanImportedName).filter(Boolean);
    const number = cells.find((cell) => /^\d{1,2}$/.test(cell)) ?? '';
    const name = cells.find((cell) => isLikelyPlayerName(cell) && !/^([a-z]{2}|ES|AR|VE|TR|NO)$/i.test(cell));
    const possibleAge = cells.find((cell) => /^\d{2}$/.test(cell) && Number(cell) >= 15 && Number(cell) <= 45 && cell !== number) || '';
    const height = normalizeImportedHeight(cells.join(' '));
    const foot = normalizeImportedFoot(cells.join(' '));
    const positionModel = normalizeImportedPosition(currentPosition);
    const { position, specificPosition } = positionModel;
    if (name) byName.set(name, { id: name, name, image: '', number, ...positionModel, position, specificPosition, age: possibleAge, height, foot, role: '', isKey: false });
  });

  return Array.from(byName.values());
};
const extractPlayersFromHtml = (html, baseUrl) => {
  const doc = new DOMParser().parseFromString(html, 'text/html');
  const transfermarktPlayers = isTransfermarktUrl(baseUrl) ? extractTransfermarktPlayers(doc, baseUrl) : [];
  if (transfermarktPlayers.length > 0) return { doc, players: transfermarktPlayers };
  if (isTransfermarktUrl(baseUrl)) return { doc, players: [] };

  const besoccerTextPlayers = isBesoccerUrl(baseUrl) ? extractBesoccerPlayersFromText(doc.body.textContent || html) : [];
  if (besoccerTextPlayers.length > 0) return { doc, players: besoccerTextPlayers };

  const besoccerPlayers = isBesoccerUrl(baseUrl) ? extractBesoccerPlayers(doc, baseUrl) : [];
  if (besoccerPlayers.length > 0) return { doc, players: besoccerPlayers };
  if (isBesoccerUrl(baseUrl)) return { doc, players: [] };

  const candidates = Array.from(doc.querySelectorAll('img'))
    .map((img) => ({
      name: img.alt?.replace(/^Image:\s*/i, '').trim(),
      image: getImageSource(img, baseUrl),
    }))
    .filter((player) => player.name && player.name.length > 3 && player.name.length < 45);

  const byName = new Map();
  candidates.forEach((player) => {
    if (!/escudo|logo|flag|bandera|apuestas|avatar|logout|laliga|bundesliga|premier|segunda|serie|ligue|transfermarkt|deadline|banner/i.test(player.name)) {
      byName.set(player.name, player);
    }
  });

  return {
    doc,
    players: byName.size > 0 ? Array.from(byName.values()).slice(0, 35) : extractImportedPlayers(doc.body.textContent ?? ''),
  };
};

const calculateAge = (dob) => {
  const birth = new Date(dob);
  const now = new Date();
  let years = now.getFullYear() - birth.getFullYear();
  const monthDiff = now.getMonth() - birth.getMonth();
  const dayDiff = now.getDate() - birth.getDate();
  if (monthDiff < 0 || (monthDiff === 0 && dayDiff < 0)) years -= 1;
  return years;
};

const formatRelativeProfileUpdate = (value) => {
  if (!value) return '';
  const timestamp = new Date(value).getTime();
  if (!Number.isFinite(timestamp)) return '';
  const elapsedDays = Math.max(0, Math.floor((Date.now() - timestamp) / 86400000));
  if (elapsedDays === 0) return 'Actualizado hoy';
  if (elapsedDays < 30) return `Actualizado hace ${elapsedDays} ${elapsedDays === 1 ? 'día' : 'días'}`;
  const months = Math.floor(elapsedDays / 30);
  if (months < 12) return `Actualizado hace ${months} ${months === 1 ? 'mes' : 'meses'}`;
  const years = Math.floor(months / 12);
  return `Actualizado hace ${years} ${years === 1 ? 'año' : 'años'}`;
};

const scoutingPriorityLabel = (value) => ({
  very_high: 'Muy alta', high: 'Alta', medium: 'Media', low: 'Baja',
}[value] || '');

const playerLabel = (dob) => (calculateAge(dob) < 23 ? 'Sub-23' : 'Senior');

const displayDorsal = (number) => (number ? number : '-');

const normalizeZoneToken = (zone) =>
  String(zone || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\./g, '')
    .replace(/ª/g, '')
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');

