    const goalsByMatch = (goalsResponse.data || []).reduce((acc, event) => {
      acc[event.partido_id] = [...(acc[event.partido_id] || []), normalizeSupabaseGoalEvent(event)];
      return acc;
    }, {});
    const quickEventsByMatch = quickEventsResponse.error
